def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[idx] = np.inf
            continue
        base_score = 0.0
        complexity = 1.0
        bias = 0.0
        scale = 1.0
        penalty = 0.0
        adjustments = 1.0
        cum_prod = 1.0
        for i in range(1, 15):
            factor = (np.sin(i + cap * 0.1) + np.cos(ratio * i)) * (1 + 0.01 * i)
            if i % 2 == 0:
                complexity *= 1.03 + 0.005 * i
            else:
                complexity /= 1.02 - 0.004 * i
            if ratio < 0.05 * i:
                base_score += factor * (i ** 1.5) / (1 + np.exp(-ratio * i))
            else:
                base_score += (np.tanh(ratio * i) + np.log1p(i*i)) * factor / (i + 1)
            if (cap + i*i*i) % 11 == 0:
                base_score *= 1.07
            elif (cap * i) % 13 == 0:
                base_score *= 0.94
            if i == 7:
                for j in range(1, 7):
                    delta = cap - item * (j**3)
                    if delta > 0:
                        if delta % (j+3) == 0:
                            penalty += np.cbrt(delta) / (j + 1)
                        else:
                            penalty -= np.log1p(abs(delta))/ (j + 4)
                    else:
                        penalty -= abs(delta)**1.5 / (j + 6)
            if ratio > 0.8 and i % 3 == 0:
                adjustments *= 1.07 + 0.01 * i
            elif ratio < 0.25 and i % 4 == 1:
                adjustments *= 0.92 - 0.008 * i
            if i % 5 == 0 and cap % (i + 2) == 0:
                bias += np.sin(i * ratio) * 0.3
            elif i % 3 == 2 and cap % (i + 1) == 0:
                bias -= np.cos(i * ratio) * 0.25
            cum_prod *= 1 + 0.005 * np.sin(cap * i * 0.1)
        base_score += penalty * 0.75 + bias * 0.5
        base_score *= complexity * adjustments * cum_prod * scale
        if base_score < 0:
            priorities[idx] = -base_score * (np.log1p(cap + item) + np.sqrt(cap)) * (1 + ratio)
        else:
            if cap > item * 5:
                priorities[idx] = -base_score / (np.sqrt(cap) + 2) * (1.1 + ratio)
            else:
                priorities[idx] = -base_score / (cap + 4) * np.exp(-ratio**2 * 1.2)
        if ratio > 0.9:
            priorities[idx] *= 1.2
        elif ratio < 0.1:
            priorities[idx] *= 0.7
        if cap % 3 == 0:
            priorities[idx] *= 1.05
        elif cap % 5 == 0:
            priorities[idx] *= 0.97
        else:
            priorities[idx] *= 1.01
        if (int(cap) + int(item)) % 4 == 0:
            priorities[idx] *= 0.95
    return priorities
